scan_table_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{
		var strInputSchema = x_snc_devtools.GetStringValue(current.inputs);

		var aInputSchema = x_snc_devtools.ParseJson(strInputSchema);
		if (x_snc_devtools.IsArray(aInputSchema) == false)
		{
			engine.finding.increment();
			return;
		}
		var grTool = x_snc_devtools.GetRecord('sn_aia_tool',current.tool);
		if (x_snc_devtools.IsValidRecord(grTool) == false)
		{
			return;
		}
		var strToolInputSchema = x_snc_devtools.GetStringValue(grTool.input_schema);
		aToolInputSchema = x_snc_devtools.ParseJson(strToolInputSchema);
		if (x_snc_devtools.IsArray(aToolInputSchema) == false)
		{
			return;
		}
		if (aToolInputSchema.length != aInputSchema.length)
		{
			engine.finding.increment();
		}
		for (var nParam = 0; nParam < aToolInputSchema.length; nParam++)
		{
			if (x_snc_devtools.GetValue(aToolInputSchema,nParam,'name')
				!= x_snc_devtools.GetValue(aInputSchema,nParam,'name'))
			{
				engine.finding.increment();
			}
			if (x_snc_devtools.GetValue(aToolInputSchema,nParam,'mandatory')
				!= x_snc_devtools.GetValue(aInputSchema,nParam,'mandatory'))
			{
				engine.finding.increment();
			}			 
		}
	}

})(engine);
